+    pub brightness: u8,
+    /// Rotation (0, 90, 180, 270)
+    pub rotation: u16,
+    /// Invert colors
+    pub inverted: bool,
+    /// X offset for display area
+    pub offset_x: u16,
+    /// Y offset for display area
+    pub offset_y: u16,
+}
+
+impl Default for DisplayConfig {
+    fn default() -> Self {
+        Self {
+            width: DISPLAY_WIDTH,
