+/// Display abstraction for BitChat
+///
+/// This provides a platform-independent interface for display operations.
+/// The actual display implementation is provided by the hardware-specific code.
+pub struct Display {
+    /// Configuration
+    config: DisplayConfig,
+    /// Current brightness
+    brightness: u8,
+    /// Display enabled
+    enabled: bool,
+    /// Dirty flag (needs redraw)
+    dirty: bool,
+}
+
+impl Display {
+    /// Create new display with configuration
+    pub fn new(config: DisplayConfig) -> Self {
+        let brightness = config.brightness;
+        Self {
+            config,
+            brightness,
+            enabled: false,
+            dirty: true,
+        }
+    }
+
+    /// Get configuration
+    pub fn config(&self) -> &DisplayConfig {
+        &self.config
+    }
+
+    /// Get display width
+    pub fn width(&self) -> u16 {
+        self.config.width
+    }
+
+    /// Get display height
+    pub fn height(&self) -> u16 {
+        self.config.height
+    }
+
+    /// Enable display
+    pub fn enable(&mut self) {
+        self.enabled = true;
+        self.dirty = true;
+    }
+
+    /// Disable display (for power saving)
+    pub fn disable(&mut self) {
+        self.enabled = false;
+    }
+
+    /// Check if display is enabled
+    pub fn is_enabled(&self) -> bool {
+        self.enabled
+    }
+
+    /// Set brightness
+    pub fn set_brightness(&mut self, brightness: u8) {
+        self.brightness = brightness;
+    }
+
+    /// Get brightness
+    pub fn brightness(&self) -> u8 {
+        self.brightness
+    }
+
+    /// Mark display as dirty (needs redraw)
+    pub fn mark_dirty(&mut self) {
+        self.dirty = true;
+    }
+
+    /// Check if display needs redraw
+    pub fn is_dirty(&self) -> bool {
+        self.dirty
+    }
+
+    /// Clear dirty flag
+    pub fn clear_dirty(&mut self) {
+        self.dirty = false;
+    }
+}
